#include <stdio.h>
#include <errno.h>
#include <string.h>

int safeDivide(int a, int b, int *result) {
  if (b == 0) {
    return -1;
  }
  *result = a / b;
  return 0;
}

int main() {
  int result;
  if (safeDivide(10, 0, &result) != 0) {
    printf("Error: Division by zero\n");
  } else {
    printf("Result: %d\n", result);
  }
  FILE *fp = fopen("nonexistent.txt", "r");
  if (fp == NULL) {
    printf("Error: %s\n", strerror(errno));
  }
  return 0;
}
